// Formata o resumo para WhatsApp
const d = $json;
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('pt-BR');

const msg = `📊 *Resumo do dia ${dateStr}*\n\n` +
  `💬 Conversas: ${d.totalConversations || 0}\n` +
  `👥 Clientes atendidos: ${d.uniqueCustomers || 0}\n` +
  `🛒 Pedidos: ${d.totalOrders || 0}\n` +
  `💰 Faturamento: R$ ${(d.revenue || 0).toFixed(2)}\n` +
  `📈 Conversão: ${d.conversionRate || 0}%\n` +
  `👤 Atend. humanos: ${d.humanHandoffs || 0}\n` +
  `⚡ Tempo médio: ${d.avgResponseTime || 0}s\n` +
  `❌ Erros: ${d.errors || 0}\n\n` +
  `🔝 *Produtos mais buscados:*\n` +
  (d.topProducts || []).slice(0, 5).map((p, i) => `${i+1}. ${p.name} (${p.searches}x)`).join('\n');

return { message: msg };
